+using NSubstitute;
+using ProjectSight.DataAccess;
+using System.Data.SqlClient;
+
+namespace ProjectSight.Tests.UnitTests.DataAccess.ServerComponents
+{
+    [TestClass]
+    public class CachedDataProviderGetDBUtcNowTests
+    {
+        private static readonly DateTimeOffset s_DbUtcNow = new DateTimeOffset(2024, 6, 1, 12, 0, 0, TimeSpan.Zero);
+        private bool m_OriginalTestRunner;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            DbUtcClockCache.Reset();
+            m_OriginalTestRunner = ApplicationConfiguration.TestRunner;
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            DbUtcClockCache.Reset();
+            ApplicationConfiguration.TestRunner = m_OriginalTestRunner;
+        }
+
+        [TestMethod]
+        public void GetDBUtcNow_WhenReaderIsOpen_FallsBackToLocalUtcWithoutDbCall()
+        {
+            ApplicationConfiguration.TestRunner = false;
+
+            var db = CreateDbHelper("Server-ReaderOpen");
+            db.ReaderIsOpen.Returns(true);
+
+#pragma warning disable CS0618
+            var provider = new CachedDataProvider(null);
+#pragma warning restore CS0618
+            provider.SetDB(db);
+
+            provider.GetDBUtcNow();
+
+            db.DidNotReceive().ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetDBUtcNow_WhenTestRunner_BypassesProcessWideCache()
+        {
+            ApplicationConfiguration.TestRunner = true;
+
+            var db = CreateDbHelper("Server-TestRunner");
+#pragma warning disable CS0618
+            var provider = new CachedDataProvider(null);
+#pragma warning restore CS0618
+            provider.SetDB(db);
+
+            provider.GetDBUtcNow();
+            provider.GetDBUtcNow();
+
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetDBUtcNow_WhenNotTestRunner_UsesProcessWideCache()
+        {
+            ApplicationConfiguration.TestRunner = false;
+
+            var db = CreateDbHelper("Server-Production");
+#pragma warning disable CS0618
+            var provider = new CachedDataProvider(null);
+#pragma warning restore CS0618
+            provider.SetDB(db);
+
+            provider.GetDBUtcNow();
+            provider.GetDBUtcNow();
+
+            db.Received(1).ExecuteScalar(Arg.Any<string>());
+        }
+
+        private static IDBHelper CreateDbHelper(string dataSource)
+        {
+            var dbUtc = s_DbUtcNow;
+            var db = Substitute.For<IDBHelper>();
+            var connection = new SqlConnection($"Data Source={dataSource};Initial Catalog=test;Integrated Security=true");
+            db.Connection.Returns(connection);
+            db.IsDisposed.Returns(false);
+            db.ExecuteScalar(Arg.Any<string>()).Returns(_ =>
+            {
+                dbUtc = dbUtc.AddMilliseconds(1);
+                return dbUtc.UtcDateTime;
+            });
+            return db;
+        }
+    }
+}

