+            Action afterResetAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+            afterResetAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_MinValueDate_ThrowsInvalidValue()
+        {
+            var db = CreateDbHelper("Server-MinValue");
