index 00000000000..523ba14ce71
--- /dev/null
+++ b/Core/Business Layer/DataAccess/ServerComponents/DbUtcClockCache.cs	
@@ -0,0 +1,296 @@
+using System;
+using System.Collections.Concurrent;
+using System.Data.SqlClient;
+using System.Threading;
+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+
+namespace ProjectSight.DataAccess
+{
+    /// <summary>
+    /// Caches the tick offset between local UTC and a SQL Server's SYSUTCDATETIME(), keyed by data source.
+    /// </summary>
+    /// <remarks>
+    /// Offset is shared across all requests in the application process. Configure refresh via DbUtcNowCacheRefreshMinutes
+    /// in DataAccessConfiguration (default 60). Stale entries are evicted when not accessed after expiry.
+    /// </remarks>
+    internal static class DbUtcClockCache
+    {
+        // ReSharper disable once StringLiteralTypo
+        private const string SQL = "SELECT SYSUTCDATETIME()";
+
+        private static readonly ConcurrentDictionary<string, CacheEntry> s_Entries =
+            new ConcurrentDictionary<string, CacheEntry>(StringComparer.OrdinalIgnoreCase);
+
+        // Throttle repeated calibration attempts per data source after failure so concurrent threads do not
+        // all retry SYSUTCDATETIME() while the underlying problem persists.
+        private static readonly ConcurrentDictionary<string, long> s_LastCalibrationFailureUtcTicks =
+            new ConcurrentDictionary<string, long>(StringComparer.OrdinalIgnoreCase);
+
+        private static readonly TimeSpan s_CalibrationFailureThrottle = TimeSpan.FromMinutes(5);
+        private const string UnknownDataSourceKey = "__unknown__";
+
+        private static readonly object s_EvictionSync = new object();
+        private static long s_LastEvictionCheckUtcTicks;
+
+        /// <summary>
+        /// Fetches a fresh DB/local UTC offset without using the process-wide cache.
+        /// </summary>
+        internal static long GetUncachedOffsetTicks(IDBHelper db)
+        {
+            // Exceptions are handled by the caller
+
+            var calibrationKey = GetCalibrationKey(db);
+            return FetchOffsetTicks(db, calibrationKey);
+        }
+
+        public static long GetOffsetTicks(IDBHelper db)
+        {
+            // Exceptions are handled by the caller
+
+            EvictStaleEntriesIfNeeded();
+
+            var dataSource = GetDataSource(db);
+            if (string.IsNullOrEmpty(dataSource))
+            {
+                return FetchOffsetTicks(db, UnknownDataSourceKey);
+            }
+
+            var entry = s_Entries.GetOrAdd(dataSource, _ => new CacheEntry());
+            return entry.GetOffsetTicks(db, dataSource, Configuration.DbUtcNowCacheRefreshInterval);
+        }
+
+        /// <summary>
+        /// Clears cached entries. Used by unit tests to isolate static cache state between runs.
+        /// </summary>
+        internal static void Reset()
+        {
+            s_Entries.Clear();
+            s_LastCalibrationFailureUtcTicks.Clear();
+            Volatile.Write(ref s_LastEvictionCheckUtcTicks, 0);
+        }
+
+        /// <summary>
+        /// Number of cached data source entries. Used by unit tests to verify eviction behavior.
+        /// </summary>
+        internal static int EntryCount => s_Entries.Count;
+
+        private static void EvictStaleEntriesIfNeeded()
+        {
+            // Exceptions are handled by the caller
+
+            var refreshInterval = Configuration.DbUtcNowCacheRefreshInterval;
+            var nowTicks = DateTime.UtcNow.Ticks;
+            var checkInterval = GetEvictionCheckInterval(refreshInterval);
+
+            if (nowTicks - Volatile.Read(ref s_LastEvictionCheckUtcTicks) < checkInterval.Ticks)
+            {
+                return;
+            }
+
+            lock (s_EvictionSync)
+            {
+                nowTicks = DateTime.UtcNow.Ticks;
+                if (nowTicks - s_LastEvictionCheckUtcTicks < checkInterval.Ticks)
+                {
+                    return;
+                }
+
+                Volatile.Write(ref s_LastEvictionCheckUtcTicks, nowTicks);
+
+                foreach (var key in s_Entries.Keys)
+                {
+                    if (s_Entries.TryGetValue(key, out var entry) && entry.IsEvictable(refreshInterval))
+                    {
+                        s_Entries.TryRemove(key, out _);
+                    }
+                }
+            }
+        }
+
+        private static TimeSpan GetEvictionCheckInterval(TimeSpan refreshInterval)
+        {
+            // Exceptions are handled by the caller
+
+            if (refreshInterval <= TimeSpan.Zero)
+            {
+                return TimeSpan.FromMinutes(1);
+            }
+
+            var interval = TimeSpan.FromTicks(refreshInterval.Ticks / 2);
+            if (interval < TimeSpan.FromMilliseconds(10))
+            {
+                interval = TimeSpan.FromMilliseconds(10);
+            }
+
+            if (interval > TimeSpan.FromMinutes(5))
+            {
+                interval = TimeSpan.FromMinutes(5);
+            }
+
+            return interval;
+        }
+
+        internal static TimeSpan GetEvictionCheckIntervalForTests(TimeSpan refreshInterval)
+        {
+            return GetEvictionCheckInterval(refreshInterval);
+        }
+
+        private static string GetDataSource(IDBHelper db)
+        {
+            // Exceptions are handled by the caller
+
+            var connection = db.Connection;
+            if (connection == null)
+            {
+                return string.Empty;
+            }
+
+            if (!string.IsNullOrEmpty(connection.DataSource))
+            {
+                return NormalizeDataSourceKey(connection.DataSource);
+            }
+
+            if (string.IsNullOrEmpty(connection.ConnectionString))
+            {
+                return string.Empty;
+            }
+
+            return NormalizeDataSourceKey(ParseDataSourceFromConnectionString(connection.ConnectionString));
+        }
+
+        /// <summary>
+        /// Normalizes a SQL data source for cache key comparison (trim, strip surrounding brackets).
+        /// Case insensitivity is handled by the cache dictionary comparer.
+        /// </summary>
+        internal static string NormalizeDataSourceKey(string dataSource)
+        {
+            // Exceptions are handled by the caller
+
+            if (string.IsNullOrWhiteSpace(dataSource))
+            {
+                return string.Empty;
+            }
+
+            var normalized = dataSource.Trim().Trim('[', ']').Trim();
+            return normalized;
+        }
+
+        internal static string ParseDataSourceFromConnectionString(string connectionString)
+        {
+            // Exceptions are handled by the caller
+
+            try
+            {
+                return new SqlConnectionStringBuilder(connectionString).DataSource;
+            }
+            catch
+            {
+                return string.Empty;
+            }
+        }
+
+        private static string GetCalibrationKey(IDBHelper db)
+        {
+            // Exceptions are handled by the caller
+
+            var dataSource = GetDataSource(db);
+            return string.IsNullOrEmpty(dataSource) ? UnknownDataSourceKey : dataSource;
+        }
+
+        internal static string GetCalibrationKeyForTests(IDBHelper db)
+        {
+            return GetCalibrationKey(db);
+        }
+
+        private static void EnsureCalibrationNotThrottled(string calibrationKey)
+        {
+            // Exceptions are handled by the caller
+
+            if (s_LastCalibrationFailureUtcTicks.TryGetValue(calibrationKey, out var lastFailureTicks)
+                && DateTime.UtcNow.Ticks - lastFailureTicks < s_CalibrationFailureThrottle.Ticks)
+            {
+                throw new InvalidOperationException("DB UTC calibration is throttled after a recent failure.");
+            }
+        }
+
+        private static void RecordCalibrationFailure(string calibrationKey)
+        {
+            // Exceptions are handled by the caller
+
+            s_LastCalibrationFailureUtcTicks[calibrationKey] = DateTime.UtcNow.Ticks;
+        }
+
+        private static long FetchOffsetTicks(IDBHelper db, string calibrationKey)
+        {
+            // Exceptions are handled by the caller
+
+            EnsureCalibrationNotThrottled(calibrationKey);
+
+            try
+            {
+                var localUtc = DateTimeOffset.UtcNow;
+                var scalar = db.ExecuteScalar(SQL);
+                if (!Global.IsDate(scalar, out DateTimeOffset dbNow) || Global.DateIsMinValue(dbNow))
+                {
+                    throw new InvalidOperationException("SYSUTCDATETIME() returned an invalid value.");
+                }
+
+                return dbNow.Ticks - localUtc.Ticks;
+            }
+            catch
+            {
+                RecordCalibrationFailure(calibrationKey);
+                throw;
+            }
+        }
+
+        private sealed class CacheEntry
+        {
+            private long m_OffsetTicks;
+            private long m_ExpiresAtUtcTicks;
+            private readonly object m_Sync = new object();
+
+            public long GetOffsetTicks(IDBHelper db, string calibrationKey, TimeSpan refreshInterval)
+            {
+                // Exceptions are handled by the caller
+
+                var expiresAt = Volatile.Read(ref m_ExpiresAtUtcTicks);
+                if (expiresAt != 0 && DateTime.UtcNow.Ticks < expiresAt)
+                {
+                    return Volatile.Read(ref m_OffsetTicks);
+                }
+
+                // Use lock (not Lazy) for refresh: offset must be re-calibrated on each TTL expiry, so a new
+                // Lazy would be required every refresh anyway. Holding the lock during ExecuteScalar serializes
+                // contending threads to a single SYSUTCDATETIME() per refresh while publishing one shared offset.
+                lock (m_Sync)
+                {
+                    if (m_ExpiresAtUtcTicks != 0 && DateTime.UtcNow.Ticks < m_ExpiresAtUtcTicks)
+                    {
+                        return m_OffsetTicks;
+                    }
+
+                    var offset = FetchOffsetTicks(db, calibrationKey);
+                    Volatile.Write(ref m_OffsetTicks, offset);
+                    Volatile.Write(ref m_ExpiresAtUtcTicks, DateTime.UtcNow.Add(refreshInterval).Ticks);
+                    return offset;
+                }
+            }
+
+            public bool IsEvictable(TimeSpan refreshInterval)
+            {
+                // Exceptions are handled by the caller
+
+                var expiresAt = Volatile.Read(ref m_ExpiresAtUtcTicks);
+                if (expiresAt == 0)
+                {
+                    return false;
+                }
+
+                // Remove entries that expired and were not re-accessed for another full refresh interval.
+                return DateTime.UtcNow.Ticks >= expiresAt + refreshInterval.Ticks;
+            }
+        }
+    }
+}
