+using NSubstitute;
+using ProjectSight.DataAccess;
+using System.Data.SqlClient;
+
+namespace ProjectSight.Tests.UnitTests.DataAccess.ServerComponents
+{
+    [TestClass]
+    public class DbUtcClockCacheTests
+    {
+        private const int PollIntervalMs = 2;
+        private static readonly TimeSpan s_ShortRefreshInterval = TimeSpan.FromMilliseconds(50);
+        private static readonly TimeSpan s_TimingTestTimeout = TimeSpan.FromSeconds(2);
+        private static readonly DateTimeOffset s_DbUtcNow = new DateTimeOffset(2024, 6, 1, 12, 0, 0, TimeSpan.Zero);
+
+        [TestInitialize]
+        public void Setup()
+        {
+            DbUtcClockCache.Reset();
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            DbUtcClockCache.Reset();
+            Configuration.ResetDbUtcNowCacheRefreshIntervalForTests();
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_ConcurrentAccess_ExecutesScalarOncePerDataSource()
+        {
+            Configuration.SetDbUtcNowCacheRefreshIntervalForTests(s_ShortRefreshInterval);
+
+            var callCount = new int[1];
+            var db = CreateDbHelper("Server-SingleFlight", callCount);
+
+            Parallel.For(0, 8, _ => DbUtcClockCache.GetOffsetTicks(db));
+            callCount[0].Should().Be(1);
+
+            var refreshAfterUtc = Environment.TickCount64 + (long)s_ShortRefreshInterval.TotalMilliseconds + 15;
+            WaitUntil(() => Environment.TickCount64 >= refreshAfterUtc, "wait for TTL expiry");
+
+            Parallel.For(0, 8, _ => DbUtcClockCache.GetOffsetTicks(db));
+            callCount[0].Should().Be(2);
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_CachesPerDataSource_CaseInsensitive()
+        {
+            var dbA = CreateDbHelper("Server-Alpha");
+            var dbB = CreateDbHelper("Server-Beta");
+            var dbALower = CreateDbHelper("server-alpha");
+
+            DbUtcClockCache.GetOffsetTicks(dbA);
+            DbUtcClockCache.GetOffsetTicks(dbB);
+            DbUtcClockCache.GetOffsetTicks(dbALower);
+
+            dbA.Received(1).ExecuteScalar(Arg.Any<string>());
+            dbB.Received(1).ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(2);
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_ReusesCachedOffsetUntilRefreshIntervalExpires()
+        {
+            Configuration.SetDbUtcNowCacheRefreshIntervalForTests(s_ShortRefreshInterval);
+
+            var db = CreateDbHelper("Server-Refresh");
+
+            DbUtcClockCache.GetOffsetTicks(db);
+            DbUtcClockCache.GetOffsetTicks(db);
+            db.Received(1).ExecuteScalar(Arg.Any<string>());
+
+            WaitUntil(() =>
+            {
+                DbUtcClockCache.GetOffsetTicks(db);
+                return ExecuteScalarWasCalled(db, 2);
+            }, "cache refresh after TTL expiry");
+
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_EvictsStaleEntriesAfterGracePeriod()
+        {
+            Configuration.SetDbUtcNowCacheRefreshIntervalForTests(s_ShortRefreshInterval);
+
+            var dbA = CreateDbHelper("Server-Evict-A");
+            var dbB = CreateDbHelper("Server-Evict-B");
+
+            DbUtcClockCache.GetOffsetTicks(dbA);
+            DbUtcClockCache.EntryCount.Should().Be(1);
+
+            WaitUntil(() =>
+            {
+                DbUtcClockCache.GetOffsetTicks(dbB);
+                return DbUtcClockCache.EntryCount == 1;
+            }, "stale entry eviction after grace period");
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_ThrottlesRepeatedCalibrationFailuresPerDataSource()
+        {
+            var db = CreateDbHelper("Server-Throttle");
+            db.ExecuteScalar(Arg.Any<string>()).Returns("not-a-date");
+
+            Action firstAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+            Action secondAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+
+            firstAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+            secondAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*throttled*");
+            db.Received(1).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetUncachedOffsetTicks_BypassesCacheAndCallsExecuteScalarEachTime()
+        {
+            var db = CreateDbHelper("Server-Uncached");
+
+            DbUtcClockCache.GetUncachedOffsetTicks(db);
+            DbUtcClockCache.GetUncachedOffsetTicks(db);
+
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_ResetClearsFailureThrottle()
+        {
+            var db = CreateDbHelper("Server-ResetThrottle");
+            db.ExecuteScalar(Arg.Any<string>()).Returns("not-a-date");
+
+            Action firstAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+            Action secondAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+
+            firstAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+            secondAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*throttled*");
+
+            DbUtcClockCache.Reset();
+
+            Action afterResetAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+            afterResetAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_MinValueDate_ThrowsInvalidValue()
+        {
+            var db = CreateDbHelper("Server-MinValue");
+            db.ExecuteScalar(Arg.Any<string>()).Returns(DateTimeOffset.MinValue);
+
+            Action act = () => DbUtcClockCache.GetOffsetTicks(db);
+
+            act.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_EmptyDataSourceAndConnectionString_UsesUncachedUnknownKeyPath()
+        {
+            var dbUtc = s_DbUtcNow;
+            var db = Substitute.For<IDBHelper>();
+            var connection = new SqlConnection();
+            db.Connection.Returns(connection);
+            db.IsDisposed.Returns(false);
+            db.ExecuteScalar(Arg.Any<string>()).Returns(_ =>
+            {
+                dbUtc = dbUtc.AddMilliseconds(1);
+                return dbUtc.UtcDateTime;
+            });
+
+            DbUtcClockCache.GetOffsetTicks(db);
+            DbUtcClockCache.GetOffsetTicks(db);
+
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(0);
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_NullConnection_UsesUncachedUnknownKeyPath()
+        {
+            var dbUtc = s_DbUtcNow;
+            var db = Substitute.For<IDBHelper>();
+            db.Connection.Returns((SqlConnection)null);
+            db.IsDisposed.Returns(false);
+            db.ExecuteScalar(Arg.Any<string>()).Returns(_ =>
+            {
+                dbUtc = dbUtc.AddMilliseconds(1);
+                return dbUtc.UtcDateTime;
+            });
+
+            DbUtcClockCache.GetOffsetTicks(db);
+            DbUtcClockCache.GetOffsetTicks(db);
+
+            db.Received(2).ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(0);
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_EmptyDataSource_UsesUnknownKeyThrottle()
+        {
+            var db = Substitute.For<IDBHelper>();
+            var connection = new SqlConnection();
+            db.Connection.Returns(connection);
+            db.IsDisposed.Returns(false);
+            db.ExecuteScalar(Arg.Any<string>()).Returns("not-a-date");
+
+            Action firstAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+            Action secondAttempt = () => DbUtcClockCache.GetOffsetTicks(db);
+
+            firstAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*invalid value*");
+            secondAttempt.Should().Throw<InvalidOperationException>()
+                .WithMessage("*throttled*");
+
+            // Unknown key path should still throttle retries and avoid creating cache entries.
+            db.Received(1).ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(0);
+        }
+
+        [TestMethod]
+        public void GetCalibrationKeyForTests_EmptySource_ReturnsUnknownKey()
+        {
+            var db = Substitute.For<IDBHelper>();
+            db.Connection.Returns(new SqlConnection());
+
+            DbUtcClockCache.GetCalibrationKeyForTests(db)
+                .Should().Be("__unknown__");
+        }
+
+        [TestMethod]
+        public void GetCalibrationKeyForTests_PopulatedSource_ReturnsNormalizedKey()
+        {
+            var db = CreateDbHelper("  [Server-Calib]  ");
+
+            DbUtcClockCache.GetCalibrationKeyForTests(db)
+                .Should().Be("Server-Calib");
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_CachesPerDataSource_TrimAndBracketsNormalized()
+        {
+            var dbTrimmed = CreateDbHelper("  Server-Alpha  ");
+            var dbBracketed = CreateDbHelper("[Server-Alpha]");
+
+            DbUtcClockCache.GetOffsetTicks(dbTrimmed);
+            DbUtcClockCache.GetOffsetTicks(dbBracketed);
+
+            dbTrimmed.Received(1).ExecuteScalar(Arg.Any<string>());
+            dbBracketed.DidNotReceive().ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(1);
+        }
+
+        [TestMethod]
+        public void NormalizeDataSourceKey_TrimsWhitespaceAndSurroundingBrackets()
+        {
+            DbUtcClockCache.NormalizeDataSourceKey("  tcp:myserver,1433  ")
+                .Should().Be("tcp:myserver,1433");
+
+            DbUtcClockCache.NormalizeDataSourceKey("[myserver\\instance]")
+                .Should().Be("myserver\\instance");
+        }
+
+        [TestMethod]
+        public void NormalizeDataSourceKey_NullOrWhitespace_ReturnsEmpty()
+        {
+            DbUtcClockCache.NormalizeDataSourceKey(null).Should().BeEmpty();
+            DbUtcClockCache.NormalizeDataSourceKey(string.Empty).Should().BeEmpty();
+            DbUtcClockCache.NormalizeDataSourceKey("   ").Should().BeEmpty();
+        }
+
+        [TestMethod]
+        public void ParseDataSourceFromConnectionString_InvalidValue_ReturnsEmpty()
+        {
+            DbUtcClockCache.ParseDataSourceFromConnectionString("not-a-valid-connection-string")
+                .Should().BeEmpty();
+        }
+
+        [TestMethod]
+        public void ParseDataSourceFromConnectionString_ValidValue_ReturnsDataSource()
+        {
+            DbUtcClockCache.ParseDataSourceFromConnectionString("Data Source=sql01\\ps;Initial Catalog=test;Integrated Security=true")
+                .Should().Be("sql01\\ps");
+        }
+
+        [TestMethod]
+        public void GetOffsetTicks_UnparseableConnectionString_FallsBackToUncachedBehavior()
+        {
+            var dbUtc = s_DbUtcNow;
+            var db = Substitute.For<IDBHelper>();
+            var connection = new SqlConnection("Initial Catalog=test;Integrated Security=true");
+            db.Connection.Returns(connection);
+            db.ExecuteScalar(Arg.Any<string>()).Returns(_ => dbUtc.UtcDateTime);
+
+            Action act = () => DbUtcClockCache.GetOffsetTicks(db);
+
+            act.Should().NotThrow();
+            db.Received(1).ExecuteScalar(Arg.Any<string>());
+            DbUtcClockCache.EntryCount.Should().Be(0);
+        }
+
+        [TestMethod]
+        public void ParseDbUtcNowCacheRefreshInterval_MissingKey_UsesDefault()
+        {
+            Configuration.ParseDbUtcNowCacheRefreshInterval(null)
+                .Should().Be(TimeSpan.FromMinutes(Configuration.DEFAULT_DB_UTC_NOW_CACHE_REFRESH_MINUTES));
+        }
+
+        [TestMethod]
+        public void ParseDbUtcNowCacheRefreshInterval_ZeroOrNegative_UsesDefault()
+        {
+            Configuration.ParseDbUtcNowCacheRefreshInterval("0")
+                .Should().Be(TimeSpan.FromMinutes(Configuration.DEFAULT_DB_UTC_NOW_CACHE_REFRESH_MINUTES));
+
+            Configuration.ParseDbUtcNowCacheRefreshInterval("-5")
+                .Should().Be(TimeSpan.FromMinutes(Configuration.DEFAULT_DB_UTC_NOW_CACHE_REFRESH_MINUTES));
+        }
+
+        [TestMethod]
+        public void ParseDbUtcNowCacheRefreshInterval_PositiveValue_UsesConfiguredMinutes()
+        {
+            Configuration.ParseDbUtcNowCacheRefreshInterval("5")
+                .Should().Be(TimeSpan.FromMinutes(5));
+        }
+
+        [TestMethod]
+        public void GetEvictionCheckIntervalForTests_NonPositive_ReturnsOneMinute()
+        {
+            DbUtcClockCache.GetEvictionCheckIntervalForTests(TimeSpan.Zero)
+                .Should().Be(TimeSpan.FromMinutes(1));
+            DbUtcClockCache.GetEvictionCheckIntervalForTests(TimeSpan.FromMilliseconds(-1))
+                .Should().Be(TimeSpan.FromMinutes(1));
+        }
+
+        [TestMethod]
+        public void GetEvictionCheckIntervalForTests_ClampsLowerBoundToTenMilliseconds()
+        {
+            DbUtcClockCache.GetEvictionCheckIntervalForTests(TimeSpan.FromMilliseconds(1))
+                .Should().Be(TimeSpan.FromMilliseconds(10));
+        }
+
+        [TestMethod]
+        public void GetEvictionCheckIntervalForTests_ClampsUpperBoundToFiveMinutes()
+        {
+            DbUtcClockCache.GetEvictionCheckIntervalForTests(TimeSpan.FromHours(24))
+                .Should().Be(TimeSpan.FromMinutes(5));
+        }
+
+        [TestMethod]
+        public void GetEvictionCheckIntervalForTests_UsesHalfRefreshIntervalWithinBounds()
+        {
+            DbUtcClockCache.GetEvictionCheckIntervalForTests(TimeSpan.FromSeconds(40))
+                .Should().Be(TimeSpan.FromSeconds(20));
+        }
+
+        private static void WaitUntil(Func<bool> condition, string description)
+        {
+            var deadline = Environment.TickCount64 + (long)s_TimingTestTimeout.TotalMilliseconds;
+            while (Environment.TickCount64 < deadline)
+            {
+                if (condition())
+                {
+                    return;
+                }
+
+                Thread.Sleep(PollIntervalMs);
+            }
+
+            Assert.Fail($"Timed out after {s_TimingTestTimeout.TotalSeconds:n0}s waiting for {description}.");
+        }
+
+        private static bool ExecuteScalarWasCalled(IDBHelper db, int expectedCount)
+        {
+            try
+            {
+                db.Received(expectedCount).ExecuteScalar(Arg.Any<string>());
+                return true;
+            }
+            catch
+            {
+                return false;
+            }
+        }
+
+        private static IDBHelper CreateDbHelper(string dataSource)
+        {
+            return CreateDbHelper(dataSource, null);
+        }
+
+        private static IDBHelper CreateDbHelper(string dataSource, int[] executeScalarCallCount)
+        {
+            var dbUtc = s_DbUtcNow;
+            var db = Substitute.For<IDBHelper>();
+            var connection = new SqlConnection($"Data Source={dataSource};Initial Catalog=test;Integrated Security=true");
+            db.Connection.Returns(connection);
+            db.IsDisposed.Returns(false);
+            db.ExecuteScalar(Arg.Any<string>()).Returns(_ =>
+            {
+                if (executeScalarCallCount != null)
+                {
+                    Interlocked.Increment(ref executeScalarCallCount[0]);
+                }
+
+                dbUtc = dbUtc.AddMilliseconds(1);
+                return dbUtc.UtcDateTime;
+            });
+            return db;
+        }
+    }
+}
